import React, { useEffect, useState, useMemo } from 'react';
import { useDispatch, useSelector } from 'react-redux';
import { useSearchParams, useNavigate } from 'react-router-dom';
import { fetchProducts } from '../store/slices/productslice';
import ProductCard from '../components/product/productcart';
import LoadingSpinner from '../components/common/lodingspinner';
import { MOCK_PRODUCTS } from '../utils/mockproducts';
import { ChevronDown, ChevronUp } from 'lucide-react';

// The nested category structure from your design
const SIDEBAR_CATEGORIES = {
    'LIVING ROOM': {
        'SOFAS': ['Fabric Sofas', 'Wooden Sofas', 'L-Shaped Sofas', 'Sofa Cum Beds', 'Recliners'],
        'SEATING': ['Lounge Chairs', 'Accent Chairs', 'Wing Chairs', 'Benches', 'Pouffes'],
        'TABLES': ['Coffee Tables', 'Side Tables', 'Console Tables', 'End Tables'],
        'STORAGE': ['TV Units', 'Bookshelves', 'Display Units', 'Shoe Racks']
    },
    'BEDROOM': {
        'BEDS': ['Solid Wood Beds', 'Upholstered Beds', 'Beds with Storage', 'King Size Beds', 'Queen Size Beds'],
        'STORAGE': ['Wardrobes', 'Chest of Drawers', 'Bedside Tables', 'Dressers'],
        'MATTRESSES': ['Memory Foam', 'Orthopedic', 'Dual Comfort', 'Coir Mattresses']
    },
    'DINING': {
        'DINING SETS': ['4 Seater Dining Sets', '6 Seater Dining Sets', '8 Seater Dining Sets', 'Extendable Dining'],
        'DINING STORAGE': ['Crockery Units', 'Kitchen Cabinets', 'Sideboards'],
        'DINING DECOR': ['Table Linens', 'Coasters', 'Dining Serveware']
    },
    'STUDY': {
        'STUDY TABLES': ['Solid Wood Tables', 'Computer Tables', 'Foldable Tables'],
        'OFFICE CHAIRS': ['Ergonomic Chairs', 'Executive Chairs', 'Study Chairs'],
        'OFFICE STORAGE': ['File Cabinets', 'Office Bookcases', 'Wall Shelves']
    }
};

const AllProductsPage = () => {
    const dispatch = useDispatch();
    const navigate = useNavigate();
    const [searchParams, setSearchParams] = useSearchParams();

    // State for the selected filter (either 'all', a main category, or a specific subcategory)
    const [selectedCategory, setSelectedCategory] = useState(
        searchParams.get('category') || 'all'
    );

    // State to control which accordion section is open in the sidebar
    const [activeAccordion, setActiveAccordion] = useState(null);

    const [sortBy, setSortBy] = useState(searchParams.get('sort') || 'newest');
    const [page, setPage] = useState(parseInt(searchParams.get('page')) || 1);

    const { items: apiItems, loading, error, totalPages } = useSelector(
        (state) => state.products
    );

    // Use mock data if no items are returned from API
    const items = useMemo(() => {
        return (apiItems && apiItems.length > 0) ? apiItems : MOCK_PRODUCTS;
    }, [apiItems]);

    const useMockData = useMemo(() => {
        return (!apiItems || apiItems.length === 0);
    }, [apiItems]);

    // Enhanced Filtering Logic to handle nested categories
    const filteredProducts = useMemo(() => {
        if (selectedCategory === 'all') return items;

        return items.filter(product => {
            // Check if the selected category matches either the main category or subcategory
            const mainMatch = product.category?.toUpperCase() === selectedCategory.toUpperCase();
            const subMatch = product.subCategory?.toUpperCase() === selectedCategory.toUpperCase();

            return mainMatch || subMatch;
        });
    }, [items, selectedCategory]);

    // Sort products
    const sortedProducts = useMemo(() => {
        return [...filteredProducts].sort((a, b) => {
            const priceA = a.variants?.[0]?.price || a.finalPrice || 0;
            const priceB = b.variants?.[0]?.price || b.finalPrice || 0;

            switch (sortBy) {
                case 'price_low':
                    return priceA - priceB;
                case 'price_high':
                    return priceB - priceA;
                case 'popular':
                    return (b.rating || 0) - (a.rating || 0);
                case 'rating':
                    return (b.rating || 0) - (a.rating || 0);
                case 'newest':
                default:
                    return 0; // Or sort by date if available in your data
            }
        });
    }, [filteredProducts, sortBy]);

    // Paginate products
    const startIdx = (page - 1) * 20;
    const paginatedProducts = sortedProducts.slice(startIdx, startIdx + 20);
    const calculatedTotalPages = Math.ceil(sortedProducts.length / 20);

    useEffect(() => {
        const params = {
            page,
            limit: 20,
        };

        if (selectedCategory !== 'all') {
            params.category = selectedCategory;
        }

        if (sortBy !== 'newest') {
            params.sort = sortBy;
        }

        // Only dispatch if API should be used
        if (!useMockData) {
            dispatch(fetchProducts(params));
        }

        // Update URL search params
        const newSearchParams = new URLSearchParams();
        if (selectedCategory !== 'all') {
            newSearchParams.set('category', selectedCategory);
        }
        if (sortBy !== 'newest') {
            newSearchParams.set('sort', sortBy);
        }
        if (page !== 1) {
            newSearchParams.set('page', page);
        }
        setSearchParams(newSearchParams);
    }, [dispatch, selectedCategory, sortBy, page, setSearchParams, useMockData]);

    // Handler for clicking a Main Category (e.g., LIVING ROOM)
    const handleMainCategoryClick = (mainCat) => {
        // Toggle the accordion open/closed
        setActiveAccordion(activeAccordion === mainCat ? null : mainCat);
        // Filter the products by the main category
        setSelectedCategory(mainCat);
        setPage(1);
    };

    // Handler for clicking a Specific Subcategory (e.g., Fabric Sofas)
    const handleSubCategoryClick = (subCat) => {
        setSelectedCategory(subCat);
        setPage(1);
    };

    const handleSortChange = (e) => {
        setSortBy(e.target.value);
        setPage(1);
    };

    const getDisplayCategory = () => {
        if (selectedCategory === 'all') return 'All Products';
        // Capitalize the first letter of each word for display
        return selectedCategory.split(' ').map(word => word.charAt(0).toUpperCase() + word.slice(1).toLowerCase()).join(' ');
    };

    if (error && !useMockData) {
        return (
            <div className="bg-gray-50 min-h-screen py-12">
                <div className="container mx-auto px-4">
                    <div className="text-center">
                        <h1 className="text-3xl font-bold text-red-600 mb-4">
                            Error Loading Products
                        </h1>
                        <p className="text-gray-600 mb-6">{error}</p>
                        <button
                            onClick={() => window.location.reload()}
                            className="bg-brand-orange text-white px-6 py-3 rounded-lg font-semibold hover:bg-orange-600 transition"
                        >
                            Try Again
                        </button>
                    </div>
                </div>
            </div>
        );
    }

    return (
        <div className="bg-gray-50 min-h-screen">
            {/* Header */}
            <div className="bg-white border-b border-gray-100 py-6 md:py-8">
                <div className="container mx-auto px-4">
                    <div className="mb-4">
                        <button
                            onClick={() => navigate('/')}
                            className="text-gray-600 text-sm hover:text-brand-orange transition flex items-center gap-1"
                        >
                            ← Back to Home
                        </button>
                    </div>
                    <h1 className="text-3xl md:text-4xl font-bold text-gray-900 mb-2">
                        {getDisplayCategory()}
                    </h1>
                    <p className="text-gray-600 text-sm">
                        Showing {paginatedProducts.length > 0 ? startIdx + 1 : 0} -{' '}
                        {startIdx + paginatedProducts.length} of {sortedProducts.length} products
                        {useMockData && <span className="text-brand-orange font-medium ml-2">(Demo Data)</span>}
                    </p>
                </div>
            </div>

            <div className="container mx-auto px-4 py-8 md:py-12">
                <div className="grid grid-cols-12 gap-6 md:gap-8">

                    {/* LEFT SIDEBAR - Categories & Filters */}
                    <div className="col-span-12 md:col-span-4 lg:col-span-3 space-y-6">

                        {/* Categories Box */}
                        <div className="bg-white rounded-lg shadow-sm border border-gray-100 p-5">
                            <h3 className="text-lg font-bold text-gray-900 mb-4">
                                Categories
                            </h3>
                            <div className="space-y-2">
                                {/* All Products Button */}
                                <button
                                    onClick={() => {
                                        setSelectedCategory('all');
                                        setActiveAccordion(null);
                                        setPage(1);
                                    }}
                                    className={`w-full text-left px-4 py-3 rounded-md font-medium transition-colors border outline-none focus:outline-none ${selectedCategory === 'all'
                                            ? 'bg-brand-orange text-white border-brand-orange shadow-inner'
                                            : 'bg-gray-50 text-gray-700 border-gray-100 hover:bg-gray-100'
                                        }`}
                                >
                                    All Products
                                </button>

                                {/* Expandable Main Categories */}
                                {Object.keys(SIDEBAR_CATEGORIES).map((mainCat) => (
                                    <div key={mainCat} className="flex flex-col">
                                        <button
                                            onClick={() => handleMainCategoryClick(mainCat)}
                                            className={`w-full flex items-center justify-between px-4 py-3 rounded-md font-medium transition-colors border outline-none focus:outline-none ${activeAccordion === mainCat
                                                    ? 'bg-orange-50 text-brand-orange border-orange-200'
                                                    : 'bg-gray-50 text-gray-700 border-gray-100 hover:bg-gray-100'
                                                }`}
                                        >
                                            <span className="capitalize">{mainCat.toLowerCase()}</span>
                                            {activeAccordion === mainCat ? <ChevronUp size={18} /> : <ChevronDown size={18} />}
                                        </button>

                                        {/* Subcategories Dropdown (Smooth reveal) */}
                                        <div className={`overflow-hidden transition-all duration-300 ease-in-out ${activeAccordion === mainCat ? 'max-h-[1000px] mt-2 opacity-100' : 'max-h-0 opacity-0'}`}>
                                            <div className="pl-4 pr-2 space-y-5 py-3 border-l-2 border-orange-200 ml-4">
                                                {Object.entries(SIDEBAR_CATEGORIES[mainCat]).map(([groupName, items]) => (
                                                    <div key={groupName}>
                                                        <h4 className="text-[11px] font-bold text-gray-400 uppercase tracking-wider mb-2">{groupName}</h4>
                                                        <ul className="space-y-2 pl-1">
                                                            {items.map(item => (
                                                                <li key={item}>
                                                                    <button
                                                                        onClick={() => handleSubCategoryClick(item)}
                                                                        className={`text-sm text-left w-full transition-colors outline-none focus:outline-none ${selectedCategory === item
                                                                                ? 'text-brand-orange font-bold'
                                                                                : 'text-gray-600 hover:text-brand-orange'
                                                                            }`}
                                                                    >
                                                                        {item}
                                                                    </button>
                                                                </li>
                                                            ))}
                                                        </ul>
                                                    </div>
                                                ))}
                                            </div>
                                        </div>
                                    </div>
                                ))}
                            </div>
                        </div>

                        {/* Sort By Box */}
                        <div className="bg-white rounded-lg shadow-sm border border-gray-100 p-5">
                            <h3 className="text-lg font-bold text-gray-900 mb-4">Sort By</h3>
                            <select
                                value={sortBy}
                                onChange={handleSortChange}
                                className="w-full px-4 py-2.5 border border-gray-200 rounded-md text-gray-700 text-sm focus:outline-none focus:ring-2 focus:ring-brand-orange cursor-pointer bg-white"
                            >
                                <option value="newest">Newest</option>
                                <option value="price_low">Price: Low to High</option>
                                <option value="price_high">Price: High to Low</option>
                                <option value="popular">Most Popular</option>
                                <option value="rating">Top Rated</option>
                            </select>
                        </div>
                    </div>

                    {/* RIGHT CONTENT - Products Grid */}
                    <div className="col-span-12 md:col-span-8 lg:col-span-9">
                        {loading && items.length === 0 ? (
                            <div className="flex justify-center items-center py-20">
                                <LoadingSpinner />
                            </div>
                        ) : paginatedProducts.length === 0 ? (
                            <div className="bg-white rounded-lg shadow-sm border border-gray-100 p-12 text-center h-full flex flex-col items-center justify-center">
                                <h3 className="text-xl font-bold text-gray-900 mb-2">
                                    No Products Found
                                </h3>
                                <p className="text-gray-600 mb-6">
                                    Try adjusting your filters or browse other categories
                                </p>
                                <button
                                    onClick={() => {
                                        setSelectedCategory('all');
                                        setActiveAccordion(null);
                                    }}
                                    className="bg-brand-orange text-white px-6 py-3 rounded-lg font-semibold hover:bg-orange-600 transition"
                                >
                                    Clear Filters
                                </button>
                            </div>
                        ) : (
                            <>
                                {/* Products Grid */}
                                <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-3 gap-6 mb-8">
                                    {paginatedProducts.map((product) => (
                                        <ProductCard key={product.id || product._id} product={product} />
                                    ))}
                                </div>

                                {/* Pagination */}
                                {calculatedTotalPages > 1 && (
                                    <div className="flex justify-center items-center gap-2 py-8">
                                        <button
                                            onClick={() => setPage(Math.max(1, page - 1))}
                                            disabled={page === 1}
                                            className="px-4 py-2 border border-gray-200 rounded-md text-gray-700 hover:border-brand-orange hover:text-brand-orange disabled:opacity-50 disabled:cursor-not-allowed transition"
                                        >
                                            Previous
                                        </button>

                                        {Array.from({ length: Math.min(calculatedTotalPages, 5) }, (_, i) => {
                                            const pageNum = page > 3 ? page - 2 + i : i + 1;
                                            return pageNum <= calculatedTotalPages ? pageNum : null;
                                        }).map(
                                            (p) => p && (
                                                <button
                                                    key={p}
                                                    onClick={() => setPage(p)}
                                                    className={`px-3.5 py-2 rounded-md transition-all duration-200 font-medium ${page === p
                                                            ? 'bg-brand-orange text-white border border-brand-orange'
                                                            : 'border border-gray-200 text-gray-700 hover:border-brand-orange hover:text-brand-orange'
                                                        }`}
                                                >
                                                    {p}
                                                </button>
                                            )
                                        )}

                                        <button
                                            onClick={() => setPage(Math.min(calculatedTotalPages, page + 1))}
                                            disabled={page === calculatedTotalPages}
                                            className="px-4 py-2 border border-gray-200 rounded-md text-gray-700 hover:border-brand-orange hover:text-brand-orange disabled:opacity-50 disabled:cursor-not-allowed transition"
                                        >
                                            Next
                                        </button>
                                    </div>
                                )}
                            </>
                        )}
                    </div>
                </div>
            </div>
        </div>
    );
};

export default AllProductsPage;
